"""
Minimal dataset implementation for testing without full pyfmridataset.
"""

from typing import Optional, Union, Tuple
import numpy as np
import pandas as pd
from dataclasses import dataclass


@dataclass
class MatrixDataset:
    """
    Simple matrix dataset for testing fMRI models.

    This is a minimal implementation that will be replaced by
    the full pyfmridataset.MatrixDataset when available.

    Parameters
    ----------
    data : np.ndarray
        2D array of shape (n_timepoints, n_voxels)
    mask : np.ndarray, optional
        Boolean mask for voxels
    tr : float, optional
        Repetition time in seconds
    """
    data: np.ndarray
    mask: Optional[np.ndarray] = None
    tr: float = 2.0

    def __post_init__(self):
        """Validate inputs."""
        if self.data.ndim != 2:
            raise ValueError(f"Data must be 2D, got {self.data.ndim}D")

        if self.mask is not None:
            if self.mask.shape[0] != self.data.shape[1]:
                raise ValueError(
                    f"Mask length ({self.mask.shape[0]}) must match "
                    f"number of voxels ({self.data.shape[1]})"
                )

    @property
    def shape(self) -> Tuple[int, int]:
        """Shape of the data (n_timepoints, n_voxels)."""
        return self.data.shape

    @property
    def n_timepoints(self) -> int:
        """Number of time points."""
        return self.data.shape[0]

    @property
    def n_voxels(self) -> int:
        """Number of voxels."""
        return self.data.shape[1]

    def get_data(self) -> np.ndarray:
        """Get the data matrix."""
        return self.data

    def get_masked_data(self) -> np.ndarray:
        """Get masked data if mask is available."""
        if self.mask is not None:
            return self.data[:, self.mask]
        return self.data

    def __repr__(self):
        return (
            f"MatrixDataset(shape={self.shape}, "
            f"tr={self.tr}, "
            f"masked={self.mask is not None})"
        )


@dataclass 
class MultiRunMatrixDataset:
    """
    Matrix dataset for multiple runs.

    Parameters
    ----------
    runs : list of np.ndarray
        List of 2D arrays, one per run
    mask : np.ndarray, optional
        Boolean mask for voxels (same for all runs)
    tr : float, optional
        Repetition time in seconds
    """
    runs: list
    mask: Optional[np.ndarray] = None
    tr: float = 2.0

    def __post_init__(self):
        """Validate inputs."""
        if not self.runs:
            raise ValueError("Must provide at least one run")

        n_voxels = self.runs[0].shape[1]
        for i, run in enumerate(self.runs):
            if run.ndim != 2:
                raise ValueError(f"Run {i} must be 2D, got {run.ndim}D")
            if run.shape[1] != n_voxels:
                raise ValueError(
                    f"Run {i} has {run.shape[1]} voxels, "
                    f"expected {n_voxels}"
                )

        if self.mask is not None:
            if self.mask.shape[0] != n_voxels:
                raise ValueError(
                    f"Mask length ({self.mask.shape[0]}) must match "
                    f"number of voxels ({n_voxels})"
                )

    @property
    def n_runs(self) -> int:
        """Number of runs."""
        return len(self.runs)

    @property
    def n_voxels(self) -> int:
        """Number of voxels."""
        return self.runs[0].shape[1]

    def get_run(self, run_idx: int) -> np.ndarray:
        """Get data for a specific run."""
        return self.runs[run_idx]

    def get_concatenated_data(self) -> np.ndarray:
        """Get all runs concatenated."""
        return np.vstack(self.runs)

    def get_run_lengths(self) -> list:
        """Get the length of each run."""
        return [run.shape[0] for run in self.runs]

    def __repr__(self):
        run_lengths = self.get_run_lengths()
        return (
            f"MultiRunMatrixDataset(n_runs={self.n_runs}, "
            f"run_lengths={run_lengths}, "
            f"n_voxels={self.n_voxels}, "
            f"tr={self.tr})"
        )


def create_dummy_dataset(
    n_timepoints: int = 100,
    n_voxels: int = 10,
    n_runs: Optional[int] = None,
    tr: float = 2.0,
    noise_level: float = 1.0,
    seed: Optional[int] = None
) -> Union[MatrixDataset, MultiRunMatrixDataset]:
    """
    Create a dummy dataset for testing.

    Parameters
    ----------
    n_timepoints : int
        Number of time points per run
    n_voxels : int  
        Number of voxels
    n_runs : int, optional
        Number of runs. If None, creates single-run dataset
    tr : float
        Repetition time
    noise_level : float
        Standard deviation of Gaussian noise
    seed : int, optional
        Random seed for reproducibility

    Returns
    -------
    dataset : MatrixDataset or MultiRunMatrixDataset
        Dummy dataset with random data
    """
    if seed is not None:
        np.random.seed(seed)

    if n_runs is None:
        # Single run
        data = np.random.randn(n_timepoints, n_voxels) * noise_level
        return MatrixDataset(data=data, tr=tr)
    else:
        # Multiple runs
        runs = []
        for _ in range(n_runs):
            run_data = np.random.randn(n_timepoints, n_voxels) * noise_level
            runs.append(run_data)
        return MultiRunMatrixDataset(runs=runs, tr=tr)

