"""
Statistical inference functions for fMRI linear models.

This module provides functions for extracting statistical measures
from fitted models, including standard errors, p-values, and test statistics.
"""

from typing import Union, Optional, Dict, Any
import numpy as np
from scipy import stats as scipy_stats

from ..models.fmri_lm import FmriLm, FmriLmResult


def standard_error(
    obj: Union[FmriLm, FmriLmResult, Dict[str, Any]],
    type: str = "estimates",
    which: Optional[Union[str, int]] = None
) -> np.ndarray:
    """
    Extract standard errors from a fitted model.

    Parameters
    ----------
    obj : FmriLm, FmriLmResult, or dict
        The fitted model or result object
    type : {'estimates', 'contrasts', 'F'}, optional
        Type of statistics to extract:
        - 'estimates': Standard errors of parameter estimates (betas)
        - 'contrasts': Standard errors of t-contrasts
        - 'F': Standard errors for F-contrasts (denominator MS)
    which : str or int, optional
        For contrasts, which contrast to extract (name or index)

    Returns
    -------
    np.ndarray
        Standard errors with shape depending on type:
        - estimates: (n_voxels, n_predictors)
        - contrasts: (n_voxels, n_contrasts) or (n_voxels,) if which specified
        - F: (n_voxels, n_fcontrasts) or (n_voxels,) if which specified
    """
    if isinstance(obj, FmriLm):
        return _extract_se_from_fmri_lm(obj, type, which)
    elif isinstance(obj, FmriLmResult):
        return _extract_se_from_result(obj, type, which)
    elif isinstance(obj, dict):
        return _extract_se_from_dict(obj, type, which)
    else:
        raise TypeError(f"Cannot extract standard errors from {type(obj)}")


def p_values(
    obj: Union[FmriLm, FmriLmResult, Dict[str, Any]],
    type: str = "estimates",
    which: Optional[Union[str, int]] = None
) -> np.ndarray:
    """
    Extract p-values from a fitted model.

    Parameters
    ----------
    obj : FmriLm, FmriLmResult, or dict
        The fitted model or result object
    type : {'estimates', 'contrasts', 'F'}, optional
        Type of statistics to extract
    which : str or int, optional
        For contrasts, which contrast to extract

    Returns
    -------
    np.ndarray
        P-values (two-tailed for t-tests, one-tailed for F-tests)
    """
    if isinstance(obj, FmriLm):
        return _extract_pvals_from_fmri_lm(obj, type, which)
    elif isinstance(obj, FmriLmResult):
        return _extract_pvals_from_result(obj, type, which)
    elif isinstance(obj, dict):
        return _extract_pvals_from_dict(obj, type, which)
    else:
        raise TypeError(f"Cannot extract p-values from {type(obj)}")


def stats(
    obj: Union[FmriLm, FmriLmResult, Dict[str, Any]],
    type: str = "estimates",
    which: Optional[Union[str, int]] = None
) -> np.ndarray:
    """
    Extract test statistics from a fitted model.

    Parameters
    ----------
    obj : FmriLm, FmriLmResult, or dict
        The fitted model or result object
    type : {'estimates', 'contrasts', 'F'}, optional
        Type of statistics to extract:
        - 'estimates': t-statistics for parameter estimates
        - 'contrasts': t-statistics for contrasts
        - 'F': F-statistics for F-contrasts
    which : str or int, optional
        For contrasts, which contrast to extract

    Returns
    -------
    np.ndarray
        Test statistics (t or F values)
    """
    if isinstance(obj, FmriLm):
        return _extract_stats_from_fmri_lm(obj, type, which)
    elif isinstance(obj, FmriLmResult):
        return _extract_stats_from_result(obj, type, which)
    elif isinstance(obj, dict):
        return _extract_stats_from_dict(obj, type, which)
    else:
        raise TypeError(f"Cannot extract statistics from {type(obj)}")


def residual_variance(
    obj: Union[FmriLm, FmriLmResult, Dict[str, Any]]
) -> np.ndarray:
    """
    Extract residual variance (sigma^2) from a fitted model.

    Parameters
    ----------
    obj : FmriLm, FmriLmResult, or dict
        The fitted model or result object

    Returns
    -------
    np.ndarray
        Residual variance for each voxel
    """
    if isinstance(obj, FmriLm):
        return obj.result.sigma ** 2
    elif isinstance(obj, FmriLmResult):
        return obj.sigma ** 2
    elif isinstance(obj, dict):
        if 'sigma2' in obj:
            return obj['sigma2']
        elif 'sigma' in obj:
            sigma = obj['sigma']
            return sigma ** 2 if isinstance(sigma, np.ndarray) else np.array([sigma ** 2])
        else:
            raise ValueError("No residual variance found in dict result")
    else:
        raise TypeError(f"Cannot extract residual variance from {type(obj)}")


def df_residual(
    obj: Union[FmriLm, FmriLmResult, Dict[str, Any]]
) -> int:
    """
    Extract residual degrees of freedom from a fitted model.

    Parameters
    ----------
    obj : FmriLm, FmriLmResult, or dict
        The fitted model or result object

    Returns
    -------
    int
        Residual degrees of freedom
    """
    if isinstance(obj, FmriLm):
        return obj.result.df_residual
    elif isinstance(obj, FmriLmResult):
        return obj.df_residual
    elif isinstance(obj, dict):
        if 'df_residual' in obj:
            return obj['df_residual']
        elif 'dfres' in obj:
            return obj['dfres']
        else:
            raise ValueError("No residual df found in dict result")
    else:
        raise TypeError(f"Cannot extract residual df from {type(obj)}")


# Helper functions for FmriLm objects
def _extract_se_from_fmri_lm(
    model: FmriLm,
    type: str,
    which: Optional[Union[str, int]]
) -> np.ndarray:
    """Extract standard errors from FmriLm object."""
    if type == "estimates":
        # Get standard errors from beta statistics
        if hasattr(model, '_beta_stats') and model._beta_stats is not None:
            se_matrix = model._beta_stats['se']
            # Return only event-related SEs if not including baseline
            event_indices = model.result.event_indices
            return se_matrix[:, event_indices]
        else:
            # Compute from scratch if not cached
            return _compute_beta_se(model)
    elif type == "contrasts":
        return _extract_contrast_se(model, which)
    elif type == "F":
        return _extract_f_contrast_se(model, which)
    else:
        raise ValueError(f"Invalid type: {type}")


def _extract_pvals_from_fmri_lm(
    model: FmriLm,
    type: str,
    which: Optional[Union[str, int]]
) -> np.ndarray:
    """Extract p-values from FmriLm object."""
    if type == "estimates":
        # Get p-values from beta statistics
        if hasattr(model, '_beta_stats') and model._beta_stats is not None:
            pval_matrix = model._beta_stats['pvalue']
            event_indices = model.result.event_indices
            return pval_matrix[:, event_indices]
        else:
            # Compute from t-statistics
            tstats = stats(model, type="estimates")
            df = model.result.df_residual
            return 2 * scipy_stats.t.cdf(-np.abs(tstats), df)
    elif type == "contrasts":
        return _extract_contrast_pvals(model, which)
    elif type == "F":
        return _extract_f_contrast_pvals(model, which)
    else:
        raise ValueError(f"Invalid type: {type}")


def _extract_stats_from_fmri_lm(
    model: FmriLm,
    type: str,
    which: Optional[Union[str, int]]
) -> np.ndarray:
    """Extract test statistics from FmriLm object."""
    if type == "estimates":
        # Get t-statistics from beta statistics
        if hasattr(model, '_beta_stats') and model._beta_stats is not None:
            tstat_matrix = model._beta_stats['tstat']
            event_indices = model.result.event_indices
            return tstat_matrix[:, event_indices]
        else:
            # Compute from betas and SEs
            betas = model.coef(include_baseline=False)
            ses = standard_error(model, type="estimates")
            return np.where(ses > np.finfo(float).eps, betas / ses, 0)
    elif type == "contrasts":
        return _extract_contrast_tstats(model, which)
    elif type == "F":
        return _extract_f_contrast_fstats(model, which)
    else:
        raise ValueError(f"Invalid type: {type}")


# Helper functions for computing statistics
def _compute_beta_se(model: FmriLm) -> np.ndarray:
    """Compute standard errors for beta coefficients."""
    # Get design matrix and compute (X'X)^-1
    X = model.model.design_matrix()
    if isinstance(X, type(None)) or X.empty:
        raise ValueError("Cannot compute standard errors without design matrix")

    X_array = X.values if hasattr(X, 'values') else X
    XtX = X_array.T @ X_array

    try:
        # Try Cholesky decomposition first
        L = np.linalg.cholesky(XtX)
        XtXinv = np.linalg.inv(L.T) @ np.linalg.inv(L)
    except np.linalg.LinAlgError:
        # Fall back to SVD for singular matrices
        XtXinv = np.linalg.pinv(XtX)

    # Get diagonal elements
    diag_XtXinv = np.diag(XtXinv)

    # Compute SEs: se(beta_i) = sigma * sqrt(diag(XtXinv)_i)
    sigma = model.result.sigma
    se_scaling = np.sqrt(diag_XtXinv)

    # Outer product for all voxels
    se_matrix = np.outer(sigma, se_scaling)

    # Return only event-related SEs
    event_indices = model.result.event_indices
    return se_matrix[:, event_indices]


def _extract_contrast_se(
    model: FmriLm,
    which: Optional[Union[str, int]]
) -> np.ndarray:
    """Extract standard errors for contrasts."""
    if not hasattr(model, '_contrast_results') or not model._contrast_results:
        raise ValueError("No contrasts have been computed for this model")

    if which is None:
        # Return all contrast SEs
        se_list = []
        for name, result in model._contrast_results.items():
            if hasattr(result, 'se'):
                se_list.append(result.se)
        return np.column_stack(se_list) if se_list else np.array([])
    else:
        # Return specific contrast SE
        if isinstance(which, str):
            if which not in model._contrast_results:
                raise ValueError(f"Contrast '{which}' not found")
            return model._contrast_results[which].se
        else:
            # Index-based access
            names = list(model._contrast_results.keys())
            if which >= len(names):
                raise IndexError(f"Contrast index {which} out of range")
            return model._contrast_results[names[which]].se


