    """Extract p-values from FmriLm object."""
    if type == "estimates":
        # Get p-values from beta statistics
        if hasattr(model, '_beta_stats') and model._beta_stats is not None:
            pval_matrix = model._beta_stats['pvalue']
            event_indices = model.result.event_indices
            return pval_matrix[:, event_indices]
        else:
            # Compute from t-statistics
            tstats = stats(model, type="estimates")
            df = model.result.df_residual
            return 2 * scipy_stats.t.cdf(-np.abs(tstats), df)
    elif type == "contrasts":
        return _extract_contrast_pvals(model, which)
    elif type == "F":
        return _extract_f_contrast_pvals(model, which)
    else:
        raise ValueError(f"Invalid type: {type}")


def _extract_stats_from_fmri_lm(
    model: FmriLm,
    type: str,
    which: Optional[Union[str, int]]
) -> np.ndarray:
    """Extract test statistics from FmriLm object."""
    if type == "estimates":
        # Get t-statistics from beta statistics
        if hasattr(model, '_beta_stats') and model._beta_stats is not None:
            tstat_matrix = model._beta_stats['tstat']
            event_indices = model.result.event_indices
            return tstat_matrix[:, event_indices]
        else:
            # Compute from betas and SEs
            betas = model.coef(include_baseline=False)
            ses = standard_error(model, type="estimates")
            return np.where(ses > np.finfo(float).eps, betas / ses, 0)
    elif type == "contrasts":
        return _extract_contrast_tstats(model, which)
    elif type == "F":
        return _extract_f_contrast_fstats(model, which)
    else:
        raise ValueError(f"Invalid type: {type}")


# Helper functions for computing statistics
def _compute_beta_se(model: FmriLm) -> np.ndarray:
    """Compute standard errors for beta coefficients."""
    # Get design matrix and compute (X'X)^-1
    X = model.model.design_matrix()
    if isinstance(X, type(None)) or X.empty:
        raise ValueError("Cannot compute standard errors without design matrix")

    X_array = X.values if hasattr(X, 'values') else X
    XtX = X_array.T @ X_array

    try:
        # Try Cholesky decomposition first
        L = np.linalg.cholesky(XtX)
        XtXinv = np.linalg.inv(L.T) @ np.linalg.inv(L)
    except np.linalg.LinAlgError:
        # Fall back to SVD for singular matrices
        XtXinv = np.linalg.pinv(XtX)

    # Get diagonal elements
    diag_XtXinv = np.diag(XtXinv)

    # Compute SEs: se(beta_i) = sigma * sqrt(diag(XtXinv)_i)
    sigma = model.result.sigma
    se_scaling = np.sqrt(diag_XtXinv)

    # Outer product for all voxels
    se_matrix = np.outer(sigma, se_scaling)

    # Return only event-related SEs
    event_indices = model.result.event_indices
    return se_matrix[:, event_indices]


