        return np.column_stack(tstat_list) if tstat_list else np.array([])
    else:
        # Return specific contrast t-stats
        if isinstance(which, str):
            if which not in model._contrast_results:
                raise ValueError(f"Contrast '{which}' not found")
            return model._contrast_results[which].tstat
        else:
            names = list(model._contrast_results.keys())
            if which >= len(names):
                raise IndexError(f"Contrast index {which} out of range")
            return model._contrast_results[names[which]].tstat


